mapper.select:
SELECT p.id, p.plan_name AS planName, p.plan_category AS planCategory, p.inspect_status AS status, DATE_FORMAT(p.inspect_time, '%Y-%m-%d %H:%i:%s') AS inspectTime, c.construction_name AS constructionName, o.organization_name AS organizationName, u.name AS inspector FROM tpc_inspection_plan p LEFT JOIN tpc_construction c ON p.construction_id = c.id LEFT JOIN tbl_organization o ON p.org_id = o.id LEFT JOIN tbl_user u ON p.inspector = u.id
AND p.plan_name LIKE CONCAT('%', #{request.planName}, '%')
AND p.plan_category = #{request.planCategory}
AND p.inspect_status = #{request.status}
AND c.construction_name LIKE CONCAT('%', #{request.constructionName}, '%')
AND o.organization_name LIKE CONCAT('%', #{request.organizationName}, '%')
AND p.inspect_time >= #{request.inspectTimeStart}
AND p.inspect_time <= #{request.inspectTimeEnd}
/*ORDER BY p.create_time DESC*/
